import { _decorator, Component, Node, Vec3, Collider2D, IPhysics2DContact } from 'cc';
import { Pooling } from '../pooling';
const { ccclass, property } = _decorator;

export interface BulletNode extends Node {
    initData?: (startPos: Vec3) => void;

}

@ccclass('BulletController')
export class BulletController extends Pooling {
    @property
    speed: number = 500;

    protected onLoad(): void {
        (this.node as BulletNode).initData = this.initData.bind(this);
        console.log(this.node)

    }

    protected start(): void {

    }

    update(deltaTime: number) {

        if (this.node.position.y > 1000) {
            this.node.active = false;
            this.node.parent = null;
        }

        this.move();
    }

    onBeginContact(selfCollider: Collider2D, otherCollider: Collider2D, contact: IPhysics2DContact | null) {
        console.log('hit');
    }

    initData(startPos: Vec3 = new Vec3(0, 0, 0)) {
        this.node.setPosition(startPos);
        this.node.active = true;
    }

    move(){
        let pos = this.node.position;
        this.node.setPosition(pos.x+ this.speed, pos.y, 0);
    }

    hitAnnounce() {
        console.log('hit')
    }

    protected onDisable(): void {
        
    }

}

